const cp = require('child_process');
const fs = require('fs');
const projRoot = '__PROJECT_ROOT__';
const docsDir = '__DOCUMENTS_DIR__';

try {
  const raw = cp.execSync('bash scripts/scan-projects.sh "' + docsDir + '" 2>&1', {cwd: projRoot, timeout: 60000, encoding: 'utf8'});
  const now = Math.floor(Date.now() / 1000);

  // Parse scan output
  const agents = raw.trim().split(String.fromCharCode(10)).filter(l => l.includes('|true|')).map((l, i) => {
    const [name, branch, last, age, uncommitted] = l.split('|');
    const days = parseInt(age) ? Math.floor((now - parseInt(age)) / 86400) : 999;
    const status = days <= 1 ? 'working' : days <= 7 ? 'idle' : 'sleeping';
    return {id: i, name, status, branch, last_commit: last, uncommitted: parseInt(uncommitted)||0, days};
  });

  // Check chat history for recent activity (overrides status)
  const historyFile = projRoot + '/tasks/.chat-history.jsonl';
  if (fs.existsSync(historyFile)) {
    const lines = fs.readFileSync(historyFile, 'utf8').trim().split(String.fromCharCode(10)).slice(-10);
    const recent = new Set();
    for (const line of lines) {
      try {
        const e = JSON.parse(line);
        const ago = (Date.now() - new Date(e.ts).getTime()) / 60000;
        if (ago < 30) recent.add(e.project);
      } catch {}
    }
    for (const a of agents) {
      if (recent.has(a.name)) a.status = 'working';
    }
  }

  return [{json:{agents, timestamp: new Date().toISOString()}}];
} catch(e) {
  return [{json:{agents:[], error: (e.stderr||'')+e.message}}];
}
